console.log("Worked"),document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".product-slider-scroll-container").forEach(e=>{let t,n,o=!1;e.addEventListener("mousedown",d=>{o=!0,e.classList.add("active"),t=d.pageX-e.offsetLeft,n=e.scrollLeft}),e.addEventListener("mouseleave",()=>{o=!1}),e.addEventListener("mouseup",()=>{o=!1}),e.addEventListener("mousemove",d=>{if(!o)return;d.preventDefault();let s=(d.pageX-e.offsetLeft-t)*2;e.scrollLeft=n-s}),e.addEventListener("click",t=>{Math.abs(e.scrollLeft-n)>5&&t.preventDefault()},!0)})});